slurm.template:
#!/bin/bash
#SBATCH --job-name={job_name}
#SBATCH --partition={partition}
#SBATCH --nodes=1
#SBATCH --ntasks-per-node={cores}
#SBATCH --mem={mem_gb}G
#SBATCH --time={walltime}
#SBATCH --output={job_name}_%j.out
#SBATCH --error={job_name}_%j.err

# Load modules
module purge
module load {module_orca}

# Working directory
cd $SLURM_SUBMIT_DIR

# ORCA path (adjust to your cluster)
ORCA=$(which orca)

# Run ORCA
$ORCA {input_file} > {job_name}.out

echo "Job finished: $(date)"

